// Compliant: validate and sanitize path
public void ReadFile(string userInput)
{
    // Validate input
    if (Path.GetInvalidFileNameChars().Any(c => userInput.Contains(c)))
    {
        throw new ArgumentException("Invalid file name");
    }

    // Use Path.Combine and GetFullPath to prevent traversal
    string basePath = "C:\\data";
    string fullPath = Path.GetFullPath(Path.Combine(basePath, userInput));

    // Verify the path is still within base directory
    if (!fullPath.StartsWith(basePath))
    {
        throw new ArgumentException("Invalid path");
    }

    string content = File.ReadAllText(fullPath);
}

// Compliant: whitelist approach
public void ReadFile(string fileId)
{
    var allowedFiles = new Dictionary<string, string>
    {
        { "file1", "C:\\data\\file1.txt" },
        { "file2", "C:\\data\\file2.txt" }
    };

    if (allowedFiles.TryGetValue(fileId, out string path))
    {
        string content = File.ReadAllText(path);
    }
}
